sql:
SELECT MIN(depth) AS shallowest_depth
FROM sites
WHERE habitat_type = 'open ocean';

SELECT species_name
FROM species_data
WHERE species_classification = 'fish' AND population_density > 10;

SELECT survey_id, COUNT(*) AS Number_of_Access_Logs
FROM access_logs
GROUP BY survey_id;

SELECT species_name, health_status 
FROM species_data 
WHERE species_id = 0;

SELECT surveys.survey_type, sites.site_name, sites.location
FROM surveys
INNER JOIN sites ON surveys.site_id = sites.site_id;

external_knowledge:
- 'wise leaders guiding them' metaphorically refers to the lead researchers of the surveys;
- 'lands where these quests took place' refer to the sites where the surveys were conducted;
- 'voyages dedicated to exploring the realm of species' pertains to surveys of type 'species'.

- 'Thriving species' metaphorically refers to species that are healthy;
- 'Numbers in the wild surpass the norm' means their population density is greater than the average;
- 'Robust presence' metaphorically indicates a high population density;
- 'Numerical dominance' refers to population density;
- 'From the most to least populous' refers to ordering the results in descending order by population density.

sql:
SELECT s.*
FROM surveys s
WHERE s.survey_id IN (
  SELECT sd.survey_id
  FROM species_data sd
) AND s.survey_id NOT IN (
  SELECT se.survey_id
  FROM environmental_data se
);

SELECT ROUND(AVG(population_density)) AS rounded_average_density
FROM species_data
WHERE survey_id = 0;
